import{_ as t,C as s,o,c as n,a5 as i,E as r}from"./chunks/framework.DiZAF7VC.js";const f=JSON.parse('{"title":"Fuzzy Search","description":"How Fuse.js uses the Bitap algorithm for approximate string matching. Configure threshold, distance, location, and scoring to control fuzzy search behavior.","frontmatter":{"title":"Fuzzy Search","description":"How Fuse.js uses the Bitap algorithm for approximate string matching. Configure threshold, distance, location, and scoring to control fuzzy search behavior."},"headers":[],"relativePath":"fuzzy-search.md","filePath":"fuzzy-search.md"}'),h={name:"fuzzy-search.md"};function l(c,e,d,p,u,k){const a=s("SearchWindowDemo");return o(),n("div",null,[e[0]||(e[0]=i('<h1 id="fuzzy-search" tabindex="-1">Fuzzy Search <a class="header-anchor" href="#fuzzy-search" aria-label="Permalink to &quot;Fuzzy Search&quot;">​</a></h1><p>Fuse.js uses a modified <a href="https://en.wikipedia.org/wiki/Bitap_algorithm" target="_blank" rel="noreferrer">Bitap algorithm</a> for approximate string matching. It finds strings that are <em>approximately</em> equal to a given pattern — tolerating typos, transpositions, and missing characters.</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes material-theme-palenight material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#C792EA;--shiki-dark:#C792EA;">const</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;"> fuse </span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">=</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;"> new</span><span style="--shiki-light:#82AAFF;--shiki-dark:#82AAFF;"> Fuse</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">([</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#C3E88D;--shiki-dark:#C3E88D;">apple</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">,</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;"> &#39;</span><span style="--shiki-light:#C3E88D;--shiki-dark:#C3E88D;">banana</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">,</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;"> &#39;</span><span style="--shiki-light:#C3E88D;--shiki-dark:#C3E88D;">orange</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">]</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">,</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;"> {</span></span>\n<span class="line"><span style="--shiki-light:#F07178;--shiki-dark:#F07178;">  includeScore</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">:</span><span style="--shiki-light:#FF9CAC;--shiki-dark:#FF9CAC;"> true</span></span>\n<span class="line"><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">}</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">fuse</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">.</span><span style="--shiki-light:#82AAFF;--shiki-dark:#82AAFF;">search</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">(</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#C3E88D;--shiki-dark:#C3E88D;">aple</span><span style="--shiki-light:#89DDFF;--shiki-dark:#89DDFF;">&#39;</span><span style="--shiki-light:#BABED8;--shiki-dark:#BABED8;">)</span></span>\n<span class="line"><span style="--shiki-light:#676E95;--shiki-light-font-style:italic;--shiki-dark:#676E95;--shiki-dark-font-style:italic;">// [{ item: &#39;apple&#39;, refIndex: 0, score: 0.25 }]</span></span></code></pre></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The Bitap algorithm computes the edit distance between the search pattern and each position in the text. The implementation uses bitwise operations for speed, with a pattern length limit of 32 characters per search term.</p><p>The algorithm produces a <strong>fuzziness score</strong> between 0 and 1:</p><ul><li><code>0</code> — perfect match</li><li><code>1</code> — complete mismatch</li></ul><p>This score is then combined with key weight and field-length norm to produce the final relevance score.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>See <a href="/articles/how-fuzzy-search-works.html">How Fuzzy Search Works</a> for an interactive walkthrough of edit distance.</p></div><h2 id="controlling-fuzziness" tabindex="-1">Controlling Fuzziness <a class="header-anchor" href="#controlling-fuzziness" aria-label="Permalink to &quot;Controlling Fuzziness&quot;">​</a></h2><p>Three options work together to determine what counts as a match:</p><h4 id="threshold" tabindex="-1"><code>threshold</code> <a class="header-anchor" href="#threshold" aria-label="Permalink to &quot;`threshold`&quot;">​</a></h4><ul><li>Default: <code>0.6</code></li></ul><p>The cutoff for the fuzziness score. A threshold of <code>0.0</code> requires a perfect match. A threshold of <code>1.0</code> matches anything.</p><h4 id="location" tabindex="-1"><code>location</code> <a class="header-anchor" href="#location" aria-label="Permalink to &quot;`location`&quot;">​</a></h4><ul><li>Default: <code>0</code></li></ul><p>The expected position of the pattern in the text. The algorithm penalizes matches that are far from this position.</p><h4 id="distance" tabindex="-1"><code>distance</code> <a class="header-anchor" href="#distance" aria-label="Permalink to &quot;`distance`&quot;">​</a></h4><ul><li>Default: <code>100</code></li></ul><p>How far from <code>location</code> a match can be before being penalized to the point of exclusion. The effective search window is:</p><p><code>threshold</code> × <code>distance</code> = maximum offset from <code>location</code></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>With defaults (<code>threshold: 0.6</code>, <code>distance: 100</code>), the pattern must appear within 60 characters of position 0 to match. For example, searching for <code>&quot;zero&quot;</code> in <code>&quot;Fuse.js is a powerful, lightweight fuzzy-search library, with zero dependencies&quot;</code> would <strong>not</strong> match — <code>&quot;zero&quot;</code> appears at index 62, just outside the window.</p></div><h4 id="ignorelocation" tabindex="-1"><code>ignoreLocation</code> <a class="header-anchor" href="#ignorelocation" aria-label="Permalink to &quot;`ignoreLocation`&quot;">​</a></h4><ul><li>Default: <code>false</code></li></ul><p>When <code>true</code>, disables location-based scoring entirely. The pattern can appear anywhere in the text and still match. This is useful when you don&#39;t know or care where the match might be.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The default options effectively search only the first ~60 characters of each field. If your data has long text fields, either increase <code>distance</code>, or set <code>ignoreLocation: true</code>.</p></div><p>Try adjusting <code>threshold</code>, <code>location</code>, and <code>distance</code> below to see how they interact.</p>',27)),r(a),e[1]||(e[1]=i('<h2 id="other-options" tabindex="-1">Other Options <a class="header-anchor" href="#other-options" aria-label="Permalink to &quot;Other Options&quot;">​</a></h2><h4 id="iscasesensitive" tabindex="-1"><code>isCaseSensitive</code> <a class="header-anchor" href="#iscasesensitive" aria-label="Permalink to &quot;`isCaseSensitive`&quot;">​</a></h4><ul><li>Default: <code>false</code></li></ul><p>When <code>true</code>, comparisons are case-sensitive.</p><h4 id="ignorediacritics" tabindex="-1"><code>ignoreDiacritics</code> <a class="header-anchor" href="#ignorediacritics" aria-label="Permalink to &quot;`ignoreDiacritics`&quot;">​</a></h4><ul><li>Default: <code>false</code></li></ul><p>When <code>true</code>, comparisons ignore diacritics (accents). For example, <code>é</code> matches <code>e</code>.</p><h4 id="findallmatches" tabindex="-1"><code>findAllMatches</code> <a class="header-anchor" href="#findallmatches" aria-label="Permalink to &quot;`findAllMatches`&quot;">​</a></h4><ul><li>Default: <code>false</code></li></ul><p>When <code>true</code>, the algorithm continues searching to the end of the text even after finding a perfect match. Useful when you need all match indices for highlighting.</p><h4 id="minmatchcharlength" tabindex="-1"><code>minMatchCharLength</code> <a class="header-anchor" href="#minmatchcharlength" aria-label="Permalink to &quot;`minMatchCharLength`&quot;">​</a></h4><ul><li>Default: <code>1</code></li></ul><p>Only return matches whose length exceeds this value. Set to <code>2</code> to ignore single-character matches.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p>The final relevance score for a result combines three factors:</p><ul><li><strong>Fuzziness score</strong> — the raw Bitap score described above</li><li><strong>Key weight</strong> — optional per-key <code>weight</code> (defaults to <code>1</code>). Higher weight = more influence on ranking. Weights are normalized internally.</li><li><strong>Field-length norm</strong> — shorter fields rank higher. A match in a title is more significant than the same match in a long description.</li></ul><p>Scores range from <code>0</code> (perfect match) to <code>1</code> (complete mismatch). Enable with <code>includeScore: true</code>.</p><h4 id="ignorefieldnorm" tabindex="-1"><code>ignoreFieldNorm</code> <a class="header-anchor" href="#ignorefieldnorm" aria-label="Permalink to &quot;`ignoreFieldNorm`&quot;">​</a></h4><ul><li>Default: <code>false</code></li></ul><p>When <code>true</code>, field length has no effect on scoring. Useful when you only care whether a term exists, not how prominent it is.</p><h4 id="fieldnormweight" tabindex="-1"><code>fieldNormWeight</code> <a class="header-anchor" href="#fieldnormweight" aria-label="Permalink to &quot;`fieldNormWeight`&quot;">​</a></h4><ul><li>Default: <code>1</code></li></ul><p>Adjusts the strength of the field-length norm. <code>0</code> is equivalent to ignoring it. <code>0.5</code> reduces the effect. <code>2.0</code> amplifies it.</p>',23))])}const m=t(h,[["render",l]]);export{f as __pageData,m as default};
